import React, { useState } from 'react';
import { View, TextInput, Text } from 'react-native';

function CelsiusInput({ celsius, onCelsiusChange }) {
  return (
    <View>
      <Text>Celsius:</Text>
      <TextInput
        value={celsius}
        onChangeText={text => onCelsiusChange(text)}
        keyboardType="numeric"
      />
    </View>
  );
}

function FahrenheitInput({ fahrenheit, onFahrenheitChange }) {
  return (
    <View>
      <Text>Fahrenheit:</Text>
      <TextInput
        value={fahrenheit}
        onChangeText={text => onFahrenheitChange(text)}
        keyboardType="numeric"
      />
    </View>
  );
}

export default function TemperatureCalculator() {
  const [celsius, setCelsius] = useState('');

  const toFahrenheit = (c) => c ? (parseFloat(c) * 9/5 + 32).toFixed(1) : '';

  const handleCelsiusChange = (value) => {
    setCelsius(value);
  };

  const handleFahrenheitChange = (value) => {
    // Convert fahrenheit to celsius
    const c = value ? ((parseFloat(value) - 32) * 5/9).toFixed(1) : '';
    setCelsius(c);
  };

  return (
    <View>
      <CelsiusInput celsius={celsius} onCelsiusChange={handleCelsiusChange} />
      <FahrenheitInput fahrenheit={toFahrenheit(celsius)} onFahrenheitChange={handleFahrenheitChange} />
    </View>
  );
}
